(function () {
  const boot = document.getElementById('bootStatus');
  const setBoot = (msg) => { if (boot) boot.textContent = msg; };
  try {
    const MONTHS = ['January','February','March','April','May','June','July','August','September','October','November','December'];
    const DESIGNATIONS = ['Intern','Community Service Medical Officer','Medical Officer Grade 1','Medical Officer Grade 2','Medical Officer Grade 3','Registrar','Medical Specialist Grade 1','Medical Specialist Grade 2','Medical Specialist Grade 3','Other…'];
    const SUPERVISORS = ['Philip Cloete', 'Sebastian De Haan', 'Paul Xafis', 'Other…'];
    const SHIFT_DEFINITIONS = [
      { key: 'WD_0800_1800', label: 'WD shift 08h00-18h00', category: 'onCall1', startTime: '08:00', endTime: '18:00', hours: 10 },
      { key: 'WD_1200_2200', label: 'WD shift 12h00-22h00', category: 'onCall1', startTime: '12:00', endTime: '22:00', hours: 10 },
      { key: 'WD_1500_2300', label: 'WD shift 15h00-23h00', category: 'onCall1', startTime: '15:00', endTime: '23:00', hours: 8 },
      { key: 'WD_2200_1000', label: 'WD shift 22h00-10h00', category: 'onCall1', startTime: '22:00', endTime: '10:00', hours: 12 },
      { key: 'WE_0800_2000', label: 'WE shift 08h00-20h00', category: 'onCall1', startTime: '08:00', endTime: '20:00', hours: 12 },
      { key: 'WE_1300_2300', label: 'WE shift 13h00-23h00', category: 'onCall1', startTime: '13:00', endTime: '23:00', hours: 10 },
      { key: 'WE_2000_1000', label: 'WE shift 20h00-10h00', category: 'onCall1', startTime: '20:00', endTime: '10:00', hours: 14 },
      { key: 'ANNUAL_LEAVE', label: 'Annual leave', category: 'leave', startTime: '', endTime: '', hours: 0 },
      { key: 'SICK_LEAVE', label: 'Sick leave', category: 'leave', startTime: '', endTime: '', hours: 0 },
      { key: 'FAMILY_RESPONSIBILITY', label: 'Family responsibility leave', category: 'leave', startTime: '', endTime: '', hours: 0 },
      { key: 'SPECIAL_LEAVE', label: 'Special leave', category: 'leave', startTime: '', endTime: '', hours: 0 },
      { key: 'PRE_NATAL', label: 'Pre-natal leave', category: 'leave', startTime: '', endTime: '', hours: 0 },
      { key: 'UNPAID_LEAVE', label: 'Unpaid leave', category: 'leave', startTime: '', endTime: '', hours: 0 },
      { key: 'WORKSHOP', label: 'Workshop', category: 'notOvertime', startTime: '', endTime: '', hours: 0 },
      { key: 'COURSE', label: 'Course', category: 'notOvertime', startTime: '', endTime: '', hours: 0 },
      { key: 'OFF_DAY', label: 'Off-day', category: 'notOvertime', startTime: '', endTime: '', hours: 0 },
      { key: 'OTHER', label: 'Other', category: 'notOvertime', startTime: '', endTime: '', hours: 0 }
    ];
    const SHIFT_CATEGORIES = [
      { key: 'normal', label: 'Normal working hours' },
      { key: 'onCall1', label: '1st on call - on site' },
      { key: 'onCall2', label: '2nd on call - off site' },
      { key: 'notOvertime', label: 'Not overtime' },
      { key: 'leave', label: 'Leave' }
    ];
    const HOLIDAYS = {
      '2026-01-01': 'Public Holiday','2026-03-21': 'Human Rights Day','2026-04-03': 'Good Friday','2026-04-06': 'Family Day','2026-05-01': 'Workers\' Day','2026-06-16': 'Youth Day','2026-08-09': 'National Women\'s Day','2026-09-23': 'Heritage Day','2026-12-16': 'Day of Reconciliation','2026-12-25': 'Christmas Day','2026-12-26': 'Day of Goodwill'
    };
    const state = { files: [], parseResults: [], rostersByDoctor: new Map(), selectedDoctor: '', selectedMonth: '', selectedYear: '', currentShifts: [], employee: { firstName:'', surname:'', persalNumber:'', designation:'', designationOther:'', supervisor:'', supervisorOther:'', signatureDate:'', timesheetName:'', shiftWorker:'', casualEmployee:'', leaveAddress:'' } };
    const $ = (id) => document.getElementById(id);
    const els = {
      dropZone: $('dropZone'), dropZoneInner: document.querySelector('#dropZone .drop-zone-inner'), rosterFiles: $('rosterFiles'), fileStatus: $('fileStatus'), extractBtn: $('extractBtn'), clearFilesBtn: $('clearFilesBtn'), uploadedFilesPanel: $('uploadedFilesPanel'), uploadedFilesList: $('uploadedFilesList'), parseMessages: $('parseMessages'), doctorSelect: $('doctorSelect'), timesheetName: $('timesheetName'), clearDoctorBtn: $('clearDoctorBtn'), monthSelect: $('monthSelect'), yearSelect: $('yearSelect'), previewBtn: $('previewBtn'), previewEmptyState: $('previewEmptyState'), previewPanel: $('previewPanel'), previewTitle: $('previewTitle'), previewSummary: $('previewSummary'), addShiftBtn: $('addShiftBtn'), sortShiftsBtn: $('sortShiftsBtn'), shiftTableBody: $('shiftTableBody'), firstName: $('firstName'), surname: $('surname'), persalNumber: $('persalNumber'), designationSelect: $('designationSelect'), designationOther: $('designationOther'), supervisorSelect: $('supervisorSelect'), supervisorOther: $('supervisorOther'), signatureDate: $('signatureDate'), leaveDetailsCard: $('leaveDetailsCard'), shiftWorkerSelect: $('shiftWorkerSelect'), casualEmployeeSelect: $('casualEmployeeSelect'), leaveAddress: $('leaveAddress'), validationPanel: $('validationPanel'), downloadDutyRosterBtn: $('downloadDutyRosterBtn'), downloadAnnexureBtn: $('downloadAnnexureBtn'), downloadLeaveBtn: $('downloadLeaveBtn'), resetAppBtn: $('resetAppBtn'), shiftRowTemplate: $('shiftRowTemplate')
    };
    function pad(n){ return String(n).padStart(2,'0'); }
    function getDayName(dateIso){ return new Date(dateIso + 'T00:00:00').toLocaleDateString('en-ZA', { weekday: 'long' }); }
    function hoursBetween(startTime,endTime){ if(!startTime||!endTime) return 0; const [sh,sm]=startTime.split(':').map(Number); const [eh,em]=endTime.split(':').map(Number); let s=sh*60+sm,e=eh*60+em; if(e<s)e+=1440; return Number(((e-s)/60).toFixed(2)); }
    function escapeHtml(v=''){ return String(v).replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;').replaceAll("'",'&#39;'); }
    function showMessage(text, type='info'){ const d=document.createElement('div'); d.className=`message ${type}`; d.textContent=text; els.parseMessages.appendChild(d); }
    function clearMessages(){ els.parseMessages.innerHTML=''; }
    function renderFiles(){ els.uploadedFilesList.innerHTML=''; els.uploadedFilesPanel.classList.toggle('hidden', !state.files.length); state.files.forEach(file=>{ const li=document.createElement('li'); li.textContent=`${file.name} (${Math.round(file.size/1024)} KB)`; els.uploadedFilesList.appendChild(li); }); els.fileStatus.textContent = state.files.length ? `${state.files.length} file(s) selected` : 'Waiting for roster file…'; }
    function updateDoctorOptions(){ els.doctorSelect.innerHTML='<option value="">— select —</option>'; [...state.rostersByDoctor.keys()].sort().forEach((doctor)=>{ const o=document.createElement('option'); o.value=doctor; o.textContent=doctor; els.doctorSelect.appendChild(o); }); }
    function rosterContainsLeave(shifts){ return shifts.some(s=>s.category==='leave'); }
    function syncConditionalFields(){ els.designationOther.classList.toggle('hidden', els.designationSelect.value!=='Other…'); els.supervisorOther.classList.toggle('hidden', els.supervisorSelect.value!=='Other…'); const hasLeave = rosterContainsLeave(state.currentShifts); els.leaveDetailsCard.classList.toggle('hidden', !hasLeave); els.downloadLeaveBtn.classList.toggle('hidden', !hasLeave); }
    function validateForDownloads(){ const issues=[]; if(!state.currentShifts.length) issues.push('No shifts selected for preview/export.'); if(!state.employee.firstName) issues.push('First name is required.'); if(!state.employee.surname) issues.push('Surname is required.'); if(!state.employee.persalNumber) issues.push('PERSAL number is required.'); if(!state.employee.designation) issues.push('Designation is required.'); if(state.employee.designation==='Other…'&&!state.employee.designationOther) issues.push('Other designation is required.'); if(!state.employee.supervisor) issues.push('Supervisor is required.'); if(state.employee.supervisor==='Other…'&&!state.employee.supervisorOther) issues.push('Other supervisor is required.'); if(!state.employee.signatureDate) issues.push('Date of signature is required.'); if(rosterContainsLeave(state.currentShifts)){ if(!state.employee.shiftWorker) issues.push('Shift worker selection is required for leave form.'); if(!state.employee.casualEmployee) issues.push('Casual employee selection is required for leave form.'); if(!state.employee.leaveAddress) issues.push('Address during leave is required.'); } els.validationPanel.classList.toggle('hidden', issues.length===0); els.validationPanel.innerHTML = issues.length ? `<strong>Required to enable downloads:</strong><ul>${issues.map(i=>`<li>${escapeHtml(i)}</li>`).join('')}</ul>` : ''; const ok=issues.length===0; els.downloadDutyRosterBtn.disabled=!ok; els.downloadAnnexureBtn.disabled=!ok; els.downloadLeaveBtn.disabled=!ok || !rosterContainsLeave(state.currentShifts); }
    function filesFromEventList(fileList){ return Array.from(fileList || []).filter(file => /\.(pdf|xlsx|xls|csv)$/i.test(file.name)); }
    function bindEmployeeFields(){ [['firstName',els.firstName],['surname',els.surname],['persalNumber',els.persalNumber],['designation',els.designationSelect],['designationOther',els.designationOther],['supervisor',els.supervisorSelect],['supervisorOther',els.supervisorOther],['signatureDate',els.signatureDate],['timesheetName',els.timesheetName],['shiftWorker',els.shiftWorkerSelect],['casualEmployee',els.casualEmployeeSelect],['leaveAddress',els.leaveAddress]].forEach(([key,el])=>{ ['input','change'].forEach(evt=>el.addEventListener(evt,()=>{ state.employee[key]=el.value; syncConditionalFields(); validateForDownloads(); })); }); }
    function populateControls(){ els.designationSelect.innerHTML='<option value="">— select —</option>'; DESIGNATIONS.forEach(v=>{ const o=document.createElement('option'); o.value=v; o.textContent=v; els.designationSelect.appendChild(o); }); els.supervisorSelect.innerHTML='<option value="">— select —</option>'; SUPERVISORS.forEach(v=>{ const o=document.createElement('option'); o.value=v; o.textContent=v; els.supervisorSelect.appendChild(o); }); els.monthSelect.innerHTML='<option value="">— select —</option>'; MONTHS.forEach(v=>{ const o=document.createElement('option'); o.value=v; o.textContent=v; els.monthSelect.appendChild(o); }); els.yearSelect.innerHTML='<option value="">— select —</option>'; [2024,2025,2026,2027].forEach(v=>{ const o=document.createElement('option'); o.value=v; o.textContent=v; els.yearSelect.appendChild(o); }); }
    function normalizeParsedEntries(results){ const byDoctor = new Map(); results.flatMap(r=>r.entries||[]).forEach(entry=>{ const doctor = (entry.doctorName || 'Unknown Doctor').trim(); const item = { id: crypto.randomUUID(), doctorName: doctor, month: entry.month, year: Number(entry.year), dateIso: entry.dateIso, dayName: entry.dayName || getDayName(entry.dateIso), shiftType: entry.shiftType || 'OTHER', shiftLabel: entry.shiftLabel || entry.comment || entry.shiftType || 'Other', startTime: entry.startTime || '', endTime: entry.endTime || '', hours: entry.hours ?? hoursBetween(entry.startTime || '', entry.endTime || ''), category: entry.category || 'notOvertime', comment: entry.comment || '', holidayName: HOLIDAYS[entry.dateIso] || '', sourceFile: entry.sourceFile || '' }; if(item.holidayName && !item.comment.includes('PUBLIC HOLIDAY')) item.comment=[item.comment,item.holidayName].filter(Boolean).join(' | '); if(!byDoctor.has(doctor)) byDoctor.set(doctor,[]); byDoctor.get(doctor).push(item); }); for(const [doctor, entries] of byDoctor.entries()){ entries.sort((a,b)=>a.dateIso.localeCompare(b.dateIso) || (a.startTime||'').localeCompare(b.startTime||'')); byDoctor.set(doctor, entries); } return byDoctor; }
    async function parseExcelRoster(file){ if(typeof ExcelJS === 'undefined') throw new Error('ExcelJS failed to load'); const buffer = await file.arrayBuffer(); const wb = new ExcelJS.Workbook(); await wb.xlsx.load(buffer); const results=[]; wb.worksheets.forEach((ws)=>{ const m = (ws.name || '').match(/([A-Za-z]+)\s+(\d{4})/); if(!m) return; const month=m[1], year=Number(m[2]); for(let rowNum=9; rowNum<=39; rowNum++){ const row=ws.getRow(rowNum); const day = Number(row.getCell(1).value); const dayName = String(row.getCell(2).text || row.getCell(2).value || '').trim(); if(!day || !dayName) continue; const dateIso=`${year}-${pad(MONTHS.findIndex(x=>x.toLowerCase()===month.toLowerCase())+1)}-${pad(day)}`; const normal=String(row.getCell(3).text || row.getCell(3).value || '').trim(); const c5=String(row.getCell(5).text || row.getCell(5).value || '').trim(); const c6=String(row.getCell(6).text || row.getCell(6).value || '').trim(); const c7=String(row.getCell(7).text || row.getCell(7).value || '').trim(); const c8=String(row.getCell(8).text || row.getCell(8).value || '').trim(); const c9=String(row.getCell(9).text || row.getCell(9).value || '').trim(); const c10=String(row.getCell(10).text || row.getCell(10).value || '').trim(); const comments=String(row.getCell(11).text || row.getCell(11).value || '').trim(); const push=(startTime,endTime,category,comment)=>{ if(!startTime&&!endTime&&!comment) return; results.push({ doctorName:'Unknown Doctor', month, year, dateIso, dayName, shiftType:'OTHER', shiftLabel:comment||'Other', startTime, endTime, category, comment:comment||'', sourceFile:file.name }); };
      if(normal){ results.push({ doctorName:'Unknown Doctor', month, year, dateIso, dayName, shiftType:/leave/i.test(normal)?'ANNUAL_LEAVE':'OTHER', shiftLabel:normal, startTime:'', endTime:'', category:/leave/i.test(normal)?'leave':'normal', comment:normal, sourceFile:file.name }); }
      push(c5,c6,'onCall1',comments); push(c7,c8,'onCall2',comments); push(c9,c10,'notOvertime',comments);
    }}); return { source:file.name, entries:results }; }
    function filterRoster(byDoctor, doctor, month, year){ return (byDoctor.get(doctor) || []).filter(item => item.month===month && Number(item.year)===Number(year)); }
    function renderShiftRows(){ els.shiftTableBody.innerHTML=''; state.currentShifts.forEach((shift)=>{ const fragment=els.shiftRowTemplate.content.cloneNode(true); const row=fragment.querySelector('tr'); row.dataset.id=shift.id; const fields=Object.fromEntries([...row.querySelectorAll('[data-field]')].map(el=>[el.dataset.field,el])); fields.date.value=shift.dateIso; fields.dayName.value=shift.dayName; fields.startTime.value=shift.startTime||''; fields.endTime.value=shift.endTime||''; fields.hours.value=shift.hours??0; fields.comment.value=shift.comment||''; SHIFT_DEFINITIONS.forEach(def=>{ const o=document.createElement('option'); o.value=def.key; o.textContent=def.label; fields.shiftType.appendChild(o); }); fields.shiftType.value=shift.shiftType; SHIFT_CATEGORIES.forEach(cat=>{ const o=document.createElement('option'); o.value=cat.key; o.textContent=cat.label; fields.category.appendChild(o); }); fields.category.value=shift.category; row.addEventListener('input',(event)=>{ const target=event.target; const item=state.currentShifts.find(s=>s.id===row.dataset.id); if(!item) return; const field=target.dataset.field; if(!field) return; item[field]=target.value; if(field==='date') item.dayName=fields.dayName.value=getDayName(target.value); if(field==='startTime'||field==='endTime') item.hours=fields.hours.value=hoursBetween(fields.startTime.value,fields.endTime.value); validateForDownloads(); syncConditionalFields(); }); row.addEventListener('click',(event)=>{ const action=event.target?.dataset?.action; if(!action) return; const index=state.currentShifts.findIndex(s=>s.id===row.dataset.id); if(index<0) return; if(action==='delete') state.currentShifts.splice(index,1); if(action==='duplicate') state.currentShifts.splice(index+1,0,{...structuredClone(state.currentShifts[index]), id: crypto.randomUUID()}); renderShiftRows(); validateForDownloads(); syncConditionalFields(); }); els.shiftTableBody.appendChild(fragment); }); }
    function renderPreview(){ if(!state.selectedDoctor||!state.selectedMonth||!state.selectedYear){ els.previewEmptyState.classList.remove('hidden'); els.previewPanel.classList.add('hidden'); return; } els.previewEmptyState.classList.add('hidden'); els.previewPanel.classList.remove('hidden'); els.previewTitle.textContent=`${state.selectedDoctor} — ${state.selectedMonth} ${state.selectedYear}`; els.previewSummary.textContent=`${state.currentShifts.length} shift item(s)`; renderShiftRows(); }
    async function handleExtract(){ clearMessages(); if(!state.files.length){ showMessage('Select at least one roster file first.','error'); return; } state.parseResults=[]; for(const file of state.files){ try { if(/\.pdf$/i.test(file.name)){ showMessage(`PDF parsing is not implemented yet for ${file.name}. Please use Excel roster files for now.`,'error'); } else { state.parseResults.push(await parseExcelRoster(file)); showMessage(`Parsed ${file.name}`,'success'); } } catch(error){ showMessage(`Failed to parse ${file.name}: ${error.message}`,'error'); } } state.rostersByDoctor = normalizeParsedEntries(state.parseResults); updateDoctorOptions(); }
    function wireEvents(){ ['dragenter','dragover'].forEach(evt=>els.dropZone.addEventListener(evt,(e)=>{ e.preventDefault(); e.stopPropagation(); els.dropZone.classList.add('dragover'); setBoot('Drop files to upload'); })); ['dragleave','drop'].forEach(evt=>els.dropZone.addEventListener(evt,(e)=>{ e.preventDefault(); e.stopPropagation(); els.dropZone.classList.remove('dragover'); })); els.dropZone.addEventListener('drop',(e)=>{ state.files=filesFromEventList(e.dataTransfer && e.dataTransfer.files); renderFiles(); setBoot(state.files.length ? `Loaded ${state.files.length} file(s). Click Extract data.` : 'No supported files dropped.'); }); els.rosterFiles.addEventListener('change',()=>{ state.files=filesFromEventList(els.rosterFiles.files); renderFiles(); setBoot(state.files.length ? `Loaded ${state.files.length} file(s). Click Extract data.` : 'No supported files selected.'); }); els.clearFilesBtn.addEventListener('click',()=>{ state.files=[]; els.rosterFiles.value=''; renderFiles(); clearMessages(); setBoot('Files cleared.'); }); els.extractBtn.addEventListener('click',handleExtract); els.doctorSelect.addEventListener('change',()=>{ state.selectedDoctor=els.doctorSelect.value; els.timesheetName.value = state.employee.timesheetName = els.doctorSelect.value; }); els.clearDoctorBtn.addEventListener('click',()=>{ state.selectedDoctor=''; els.doctorSelect.value=''; state.currentShifts=[]; renderPreview(); validateForDownloads(); }); els.monthSelect.addEventListener('change',()=> state.selectedMonth=els.monthSelect.value); els.yearSelect.addEventListener('change',()=> state.selectedYear=els.yearSelect.value); els.previewBtn.addEventListener('click',()=>{ state.selectedDoctor=els.doctorSelect.value; state.selectedMonth=els.monthSelect.value; state.selectedYear=els.yearSelect.value; state.currentShifts=filterRoster(state.rostersByDoctor, state.selectedDoctor, state.selectedMonth, state.selectedYear); renderPreview(); syncConditionalFields(); validateForDownloads(); }); els.addShiftBtn.addEventListener('click',()=>{ const monthIndex=MONTHS.indexOf(state.selectedMonth)+1||1; const baseDate=`${state.selectedYear||2026}-${pad(monthIndex)}-01`; state.currentShifts.push({ id:crypto.randomUUID(), doctorName:state.selectedDoctor, month:state.selectedMonth, year:Number(state.selectedYear||2026), dateIso:baseDate, dayName:getDayName(baseDate), shiftType:'OTHER', shiftLabel:'Other', startTime:'', endTime:'', hours:0, category:'notOvertime', comment:''}); renderShiftRows(); validateForDownloads(); }); els.sortShiftsBtn.addEventListener('click',()=>{ state.currentShifts.sort((a,b)=>a.dateIso.localeCompare(b.dateIso)||(a.startTime||'').localeCompare(b.startTime||'')); renderShiftRows(); }); els.resetAppBtn.addEventListener('click',()=>{ state.files=[]; state.parseResults=[]; state.rostersByDoctor=new Map(); state.selectedDoctor=''; state.selectedMonth=''; state.selectedYear=''; state.currentShifts=[]; Object.keys(state.employee).forEach(k=>state.employee[k]=''); els.rosterFiles.value=''; document.querySelectorAll('input, select, textarea').forEach((el)=>{ if(el.type==='file') return; if(el.tagName==='SELECT') el.selectedIndex=0; else el.value=''; }); renderFiles(); clearMessages(); updateDoctorOptions(); renderPreview(); syncConditionalFields(); validateForDownloads(); setBoot('App reset.'); }); }
    populateControls();
    bindEmployeeFields();
    wireEvents();
    renderFiles();
    updateDoctorOptions();
    syncConditionalFields();
    validateForDownloads();
    setBoot('App loaded. Click the upload area to choose files.');
  } catch (error) {
    setBoot('App failed to initialize: ' + error.message);
    console.error(error);
  }
})();